from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    from collections import defaultdict

    # Group predicates and objects by subject
    subj_props: dict[str, list[tuple[str, str]]] = defaultdict(list)
    for t in triples:
        subj_props[t.subject].append((t.predicate, t.object))

    sentences: list[str] = []

    for subj, props in subj_props.items():
        # Separate genre objects to handle them together
        genre_objs: list[str] = []
        other_props: list[tuple[str, str]] = []

        for p, o in props:
            if p == "genre":
                genre_objs.append(o)
            else:
                other_props.append((p, o))

        # Start building the main clause
        clause = subj

        # Occupation (if any) goes directly after the subject
        occ = [o for p, o in other_props if p == "occupation"]
        if occ:
            clause += f" works as {occ[0]}"
            # remove so we don't repeat later
            other_props = [(p, o) for p, o in other_props if p != "occupation"]

        # Collect attribute phrases
        attr_phrases: list[str] = []
        for p, o in other_props:
            if p == "origin":
                attr_phrases.append(f"originates from {o}")
            elif p in ("birthPlace", "birthDate", "birthYear"):
                attr_phrases.append(f"was born in {o}")
            elif p == "deathPlace":
                attr_phrases.append(f"died in {o}")
            elif p == "deathDate":
                attr_phrases.append(f"died on {o}")
            elif p == "nationality":
                attr_phrases.append(f"has nationality {o}")
            elif p == "instrument":
                attr_phrases.append(f"plays the {o}")
            elif p == "associatedBand/associatedMusicalArtist":
                attr_phrases.append(f"is associated with {o}")
            elif p == "recordLabel":
                attr_phrases.append(f"is signed to {o}")
            elif p == "background":
                attr_phrases.append(f"has a background as {o}")
            elif p == "activeYearsStartYear":
                attr_phrases.append(f"started activity in {o}")
            elif p == "activeYearsEndYear":
                attr_phrases.append(f"ended activity in {o}")
            # relational predicates are ignored in the main clause for brevity

        if attr_phrases:
            clause += " who " + ", ".join(attr_phrases)

        # Add genre information
        if genre_objs:
            # join multiple genres naturally
            if len(genre_objs) == 1:
                genre_str = genre_objs[0]
            else:
                genre_str = ", ".join(genre_objs[:-1]) + " and " + genre_objs[-1]
            # avoid double "music" if already present
            if genre_str.lower().endswith(" music"):
                clause += f" plays {genre_str.lower()}"
            else:
                clause += f" plays {genre_str.lower()} music"

        sentences.append(clause)

    # Combine sentences for different subjects
    if len(sentences) == 1:
        return sentences[0] + "."
    else:
        return "; ".join(sentences) + "."

# EVOLVE-BLOCK-END

